import React, { useEffect, useState } from 'react';
import api from '../services/api';

export default function Patients(){
  const [patients, setPatients] = useState([]);
  const [form, setForm] = useState({name:'',age:'',gender:'',contact:'',address:''});

  async function load(){
    const res = await api.get('/patients');
    setPatients(res.data);
  }
  useEffect(()=>{load()},[]);

  async function handleAdd(e){
    e.preventDefault();
    await api.post('/patients', form);
    setForm({name:'',age:'',gender:'',contact:'',address:''});
    load();
  }

  async function handleDelete(id){
    await api.delete(`/patients/${id}`);
    load();
  }

  return (
    <div>
      <h2>Patients</h2>
      <form className="form" onSubmit={handleAdd}>
        <input placeholder="Name" value={form.name} onChange={e=>setForm({...form,name:e.target.value})} required />
        <input placeholder="Age" value={form.age} onChange={e=>setForm({...form,age:e.target.value})} required />
        <input placeholder="Gender" value={form.gender} onChange={e=>setForm({...form,gender:e.target.value})} />
        <input placeholder="Contact" value={form.contact} onChange={e=>setForm({...form,contact:e.target.value})} />
        <input placeholder="Address" value={form.address} onChange={e=>setForm({...form,address:e.target.value})} />
        <button className="btn">Add Patient</button>
      </form>

      <table className="table">
        <thead><tr><th>ID</th><th>Name</th><th>Age</th><th>Contact</th><th>Actions</th></tr></thead>
        <tbody>
          {patients.map(p=> (
            <tr key={p.id}>
              <td>{p.id}</td>
              <td>{p.name}</td>
              <td>{p.age}</td>
              <td>{p.contact}</td>
              <td className="flex">
                <button className="btn secondary" onClick={()=>navigator.clipboard.writeText(p.id)}>Copy ID</button>
                <button className="btn" onClick={()=>handleDelete(p.id)}>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
